// CONFIGURATION — API keys injected via automation
return [{
  json: {
    anthropicApiKey: 'YOUR_ANTHROPIC_API_KEY',
    appUrl: 'https://autoapply.works',
    webhookSecret: 'YOUR_N8N_WEBHOOK_SECRET',
    adzunaAppId: 'e2af75b6',
    adzunaAppKey: 'YOUR_ADZUNA_APP_KEY',
    jsearchApiKey: 'YOUR_JSEARCH_API_KEY',
    joobleApiKey: '',
    reedApiKey: ''
  }
}];

// Normalize active-users payload into per-user pipeline items
const items = $input.all();
const users = [];

for (const item of items) {
  const payload = item.json || {};
  const rows = Array.isArray(payload.users) ? payload.users : [payload];

  for (const row of rows) {
    if (row && row.id && row.masterCvText) {
      users.push({
        json: {
          userId: row.id,
          email: row.email || '',
          name: row.name || '',
          subscriptionStatus: row.subscriptionStatus || 'free',
          creditsRemaining: typeof row.creditsRemaining === 'number' ? row.creditsRemaining : 0,
          targetTitles: Array.isArray(row.targetTitles) ? row.targetTitles : ['software engineer'],
          locations: Array.isArray(row.locations) ? row.locations : ['remote'],
          remotePreference: row.remotePreference || 'any',
          salaryMin: typeof row.salaryMin === 'number' ? row.salaryMin : 0,
          industries: Array.isArray(row.industries) ? row.industries : [],
          masterCvText: row.masterCvText
        }
      });
    }
  }
}

if (users.length === 0) {
  return [];
}

return users;

// Flatten jobs returned by Fetch Jobs via App API (all incoming items)
const inputs = $input.all();
const out = [];

for (const item of inputs) {
  const payload = item && item.json && typeof item.json === 'object' ? item.json : null;
  if (!payload) continue;

  if (payload.externalId && payload.userId && payload.title && String(payload.description || '').length > 50) {
    out.push({ json: payload });
    continue;
  }

  const jobs = Array.isArray(payload.jobs) ? payload.jobs : [];
  for (const job of jobs) {
    if (job && typeof job === 'object' && job.externalId && job.title && String(job.description || '').length > 50) {
      out.push({ json: job });
    }
  }
}

return out;

// Parse scoring response, carry forward job + user data
const item = $input.first();
const prev = $('Fetch & Normalize All Job Sources').item;

function parseJsonFromText(rawText) {
  const text = typeof rawText === 'string' ? rawText : '';
  const candidates = [];

  if (text) candidates.push(text);

  const fenced = text.match(new RegExp("\x60\x60\x60(?:json)?\\s*([\\s\\S]*?)\x60\x60\x60", "i"));
  if (fenced && fenced[1]) candidates.unshift(fenced[1]);

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidates.push(text.slice(firstBrace, lastBrace + 1));
  }

  for (const candidate of candidates) {
    try {
      return JSON.parse(String(candidate).trim());
    } catch {}
  }

  return null;
}

const text = item && item.json && Array.isArray(item.json.content) && item.json.content[0]
  ? (item.json.content[0].text || '')
  : '';
const parsed = parseJsonFromText(text);

if (!parsed || typeof parsed !== 'object') {
  return [{ json: {
    ...prev.json,
    compatibilityScore: 0,
    atsKeywords: [],
    matchingStrengths: [],
    gaps: [],
    recommendation: 'skip',
    scoringParseError: true
  }}];
}

return [{ json: {
  ...prev.json,
  compatibilityScore: parsed.compatibility_score || 0,
  atsKeywords: Array.isArray(parsed.ats_keywords) ? parsed.ats_keywords : [],
  matchingStrengths: Array.isArray(parsed.matching_strengths) ? parsed.matching_strengths : [],
  gaps: Array.isArray(parsed.gaps) ? parsed.gaps : [],
  recommendation: parsed.recommendation || 'skip',
  scoringParseError: false
}}];

// Parse tailoring response
const item = $input.first();
const prev = $('Score >= 70?').first().json;

function parseJsonFromText(rawText) {
  const text = typeof rawText === 'string' ? rawText : '';
  const candidates = [];

  if (text) candidates.push(text);

  const fenced = text.match(new RegExp("\x60\x60\x60(?:json)?\\s*([\\s\\S]*?)\x60\x60\x60", "i"));
  if (fenced && fenced[1]) candidates.unshift(fenced[1]);

  const firstBrace = text.indexOf('{');
  const lastBrace = text.lastIndexOf('}');
  if (firstBrace >= 0 && lastBrace > firstBrace) {
    candidates.push(text.slice(firstBrace, lastBrace + 1));
  }

  for (const candidate of candidates) {
    try {
      return JSON.parse(String(candidate).trim());
    } catch {}
  }

  return null;
}

const text = item && item.json && Array.isArray(item.json.content) && item.json.content[0]
  ? (item.json.content[0].text || '')
  : '';
const parsed = parseJsonFromText(text);

if (!parsed || typeof parsed !== 'object') {
  if (text && text.trim().length >= 200) {
    return [{ json: {
      ...prev,
      tailoredCvMarkdown: text.trim(),
      coverLetterMarkdown: '',
      status: 'tailored',
      tailoringParseError: true,
      tailoringParseFallback: 'raw_text'
    }}];
  }

  return [{ json: {
    ...prev,
    tailoredCvMarkdown: '',
    coverLetterMarkdown: '',
    status: 'discovered',
    tailoringParseError: true
  }}];
}

const tailoredCvMarkdown = parsed.tailored_cv_markdown || parsed.tailoredCvMarkdown || parsed.cv_markdown || '';
const coverLetterMarkdown = parsed.motivation_letter_markdown || parsed.cover_letter_markdown || parsed.coverLetterMarkdown || '';

if (!tailoredCvMarkdown && !coverLetterMarkdown && text && text.trim().length >= 200) {
  return [{ json: {
    ...prev,
    tailoredCvMarkdown: text.trim(),
    coverLetterMarkdown: '',
    status: 'tailored',
    tailoringParseError: true,
    tailoringParseFallback: 'raw_text'
  }}];
}

return [{ json: {
  ...prev,
  tailoredCvMarkdown,
  coverLetterMarkdown,
  status: tailoredCvMarkdown ? 'tailored' : 'discovered',
  tailoringParseError: false
}}];

// For low-scoring jobs (score < 70), mark as discovered only
const item = $input.first().json;

return [{ json: {
  ...item,
  tailoredCvMarkdown: null,
  coverLetterMarkdown: null,
  status: 'discovered'
}}];

// Collect all processed jobs (tailored + discovered) and callback to web app
const items = $input.all();
const config = $('Load Config').first().json;

if (items.length === 0) return [];

const byUser = {};
for (const item of items) {
  const d = item.json;
  if (!d || !d.userId) continue;
  if (!byUser[d.userId]) byUser[d.userId] = [];
  byUser[d.userId].push({
    externalId: d.externalId,
    title: d.title,
    company: d.company,
    location: d.location,
    description: d.description,
    source: d.source,
    url: d.url,
    salary: d.salary,
    postedAt: d.postedAt,
    compatibilityScore: d.compatibilityScore,
    atsKeywords: d.atsKeywords,
    matchingStrengths: d.matchingStrengths,
    gaps: d.gaps,
    recommendation: d.recommendation,
    tailoredCvMarkdown: d.tailoredCvMarkdown || null,
    coverLetterMarkdown: d.coverLetterMarkdown || null,
    status: d.status,
    runId: d.runId || null
  });
}

const appUrl = config.appUrl || 'https://autoapply.works';
const secret = config.webhookSecret || '';
const callbackErrors = [];
let processed = 0;

for (const [userId, apps] of Object.entries(byUser)) {
  const runId = apps[0] && apps[0].runId ? String(apps[0].runId) : String($execution.id || Date.now());
  try {
    const resp = await fetch(appUrl + '/api/webhooks/n8n', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': secret,
        'x-run-id': runId
      },
      body: JSON.stringify({
        type: 'new_applications',
        runId,
        data: { userId, applications: apps }
      })
    });

    if (!resp.ok) {
      const body = await resp.text();
      callbackErrors.push({ userId, status: resp.status, body: String(body || '').slice(0, 300) });
      continue;
    }

    processed += apps.length;
  } catch (e) {
    callbackErrors.push({ userId, status: null, body: e && e.message ? e.message : 'network_error' });
  }
}

if (callbackErrors.length > 0) {
  throw new Error('batch_save_callback_failed:' + JSON.stringify(callbackErrors).slice(0, 500));
}

return [{ json: { processed, users: Object.keys(byUser).length } }];

// Error handler - log to workflow_errors via web app
const error = $input.first().json;
const config = $('Load Config').first().json;
const appUrl = config.appUrl || 'https://autoapply.works';
const secret = config.webhookSecret || '';
const runId = String($execution.id || Date.now());

try {
  await fetch(appUrl + '/api/webhooks/n8n', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': secret,
      'x-run-id': runId
    },
    body: JSON.stringify({
      type: 'workflow_error',
      runId,
      data: {
        workflowId: 'job-discovery-pipeline',
        nodeName: error.node && error.node.name ? error.node.name : 'unknown',
        errorType: error.type || 'UNKNOWN',
        message: error.message || 'Unknown error',
        payload: JSON.stringify(error)
      }
    })
  });
} catch (e) {
  console.log('Error logging failed:', e && e.message ? e.message : e);
}

return [{ json: { logged: true } }];

// CONFIGURATION — API keys injected via automation
return [{
  json: {
    anthropicApiKey: 'YOUR_ANTHROPIC_API_KEY',
    appUrl: 'https://autoapply.works',
    webhookSecret: 'YOUR_N8N_WEBHOOK_SECRET',
    adzunaAppId: 'e2af75b6',
    adzunaAppKey: 'YOUR_ADZUNA_APP_KEY',
    jsearchApiKey: 'YOUR_JSEARCH_API_KEY',
    joobleApiKey: '',
    reedApiKey: ''
  }
}];

// Split users into individual items for processing
const items = $input.all();
const users = [];

for (const item of items) {
  const row = item.json;
  if (row.id && row.masterCvText) {
    users.push({
      json: {
        userId: row.id,
        email: row.email,
        name: row.name,
        subscriptionStatus: row.subscriptionStatus,
        creditsRemaining: row.creditsRemaining,
        targetTitles: row.targetTitles || ['software engineer'],
        locations: row.locations || ['remote'],
        remotePreference: row.remotePreference || 'any',
        salaryMin: row.salaryMin || 0,
        industries: row.industries || [],
        masterCvText: row.masterCvText
      }
    });
  }
}

if (users.length === 0) {
  return [];
}

return users;

// Fetch jobs from ALL sources for this user, normalize, and deduplicate
const user = $input.first().json;
const config = $('Load Config').first().json;
const searchTitle = (user.targetTitles[0] || 'software engineer').trim();
const searchLocation = (user.locations[0] || '').trim();

const allJobs = [];

// Helper: safe fetch with timeout
async function safeFetch(url, options = {}) {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), 15000);
  try {
    const resp = await fetch(url, { ...options, signal: controller.signal });
    clearTimeout(timeout);
    if (!resp.ok) return null;
    return await resp.json();
  } catch (e) {
    clearTimeout(timeout);
    return null;
  }
}

// 1. ADZUNA
if (config.adzunaAppId && config.adzunaAppKey) {
  try {
    const adzunaUrl = `https://api.adzuna.com/v1/api/jobs/us/search/1?app_id=${config.adzunaAppId}&app_key=${config.adzunaAppKey}&what=${encodeURIComponent(searchTitle)}&where=${encodeURIComponent(searchLocation)}&results_per_page=15&content-type=application/json`;
    const data = await safeFetch(adzunaUrl);
    if (data?.results) {
      for (const j of data.results) {
        allJobs.push({
          externalId: `adzuna-${j.id}`,
          title: j.title || '',
          company: j.company?.display_name || 'Unknown',
          location: j.location?.display_name || '',
          description: j.description || '',
          source: 'adzuna',
          url: j.redirect_url || '',
          salary: j.salary_is_predicted === '0' ? `${j.salary_min}-${j.salary_max}` : null,
          postedAt: j.created ? new Date(j.created).toISOString() : null
        });
      }
    }
  } catch (e) { /* adzuna failed, continue */ }
}

// 2. THE MUSE (free, no key needed)
try {
  const museUrl = `https://www.themuse.com/api/public/jobs?category=Engineering&level=Mid%20Level&page=1`;
  const data = await safeFetch(museUrl);
  if (data?.results) {
    for (const j of data.results) {
      allJobs.push({
        externalId: `themuse-${j.id}`,
        title: j.name || '',
        company: j.company?.name || 'Unknown',
        location: j.locations?.map(l => l.name).join(', ') || '',
        description: (j.contents || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        source: 'themuse',
        url: j.refs?.landing_page || '',
        salary: null,
        postedAt: j.publication_date || null
      });
    }
  }
} catch (e) { /* themuse failed */ }

// 3. REMOTIVE (free, no key needed)
try {
  const remotiveUrl = `https://remotive.com/api/remote-jobs?search=${encodeURIComponent(searchTitle)}&limit=15`;
  const data = await safeFetch(remotiveUrl);
  if (data?.jobs) {
    for (const j of data.jobs) {
      allJobs.push({
        externalId: `remotive-${j.id}`,
        title: j.title || '',
        company: j.company_name || 'Unknown',
        location: j.candidate_required_location || 'Remote',
        description: (j.description || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        source: 'remotive',
        url: j.url || '',
        salary: j.salary || null,
        postedAt: j.publication_date || null
      });
    }
  }
} catch (e) { /* remotive failed */ }

// 4. ARBEITNOW (free, no key needed)
try {
  const arbeitnowUrl = `https://www.arbeitnow.com/api/job-board-api?search=${encodeURIComponent(searchTitle)}&page=1`;
  const data = await safeFetch(arbeitnowUrl);
  if (data?.data) {
    for (const j of data.data) {
      allJobs.push({
        externalId: `arbeitnow-${j.slug || j.id || Date.now()}`,
        title: j.title || '',
        company: j.company_name || 'Unknown',
        location: j.location || '',
        description: (j.description || '').replace(/<[^>]*>/g, '').substring(0, 3000),
        source: 'arbeitnow',
        url: j.url || '',
        salary: null,
        postedAt: j.created_at || null
      });
    }
  }
} catch (e) { /* arbeitnow failed */ }

// 5. JSEARCH (RapidAPI, needs key)
if (config.jsearchApiKey) {
  try {
    const query = `${searchTitle} in ${searchLocation || 'remote'}`;
    const jsearchUrl = `https://jsearch.p.rapidapi.com/search?query=${encodeURIComponent(query)}&page=1&num_pages=1`;
    const data = await safeFetch(jsearchUrl, {
      headers: {
        'X-RapidAPI-Key': config.jsearchApiKey,
        'X-RapidAPI-Host': 'jsearch.p.rapidapi.com'
      }
    });
    if (data?.data) {
      for (const j of data.data) {
        allJobs.push({
          externalId: `jsearch-${j.job_id}`,
          title: j.job_title || '',
          company: j.employer_name || 'Unknown',
          location: j.job_city ? `${j.job_city}, ${j.job_state || j.job_country}` : (j.job_country || ''),
          description: (j.job_description || '').substring(0, 3000),
          source: 'jsearch',
          url: j.job_apply_link || j.job_google_link || '',
          salary: j.job_min_salary ? `${j.job_min_salary}-${j.job_max_salary}` : null,
          postedAt: j.job_posted_at_datetime_utc || null
        });
      }
    }
  } catch (e) { /* jsearch failed */ }
}

// 6. JOOBLE (needs key)
if (config.joobleApiKey) {
  try {
    const data = await safeFetch(`https://jooble.org/api/${config.joobleApiKey}`, {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ keywords: searchTitle, location: searchLocation, page: 1 })
    });
    if (data?.jobs) {
      for (const j of data.jobs) {
        allJobs.push({
          externalId: `jooble-${j.id || Date.now()}`,
          title: j.title || '',
          company: j.company || 'Unknown',
          location: j.location || '',
          description: (j.snippet || '').substring(0, 3000),
          source: 'jooble',
          url: j.link || '',
          salary: j.salary || null,
          postedAt: j.updated || null
        });
      }
    }
  } catch (e) { /* jooble failed */ }
}

// 7. REED (needs key, basic auth)
if (config.reedApiKey) {
  try {
    const reedAuth = btoa(config.reedApiKey + ':');
    const reedUrl = `https://www.reed.co.uk/api/1.0/search?keywords=${encodeURIComponent(searchTitle)}&locationName=${encodeURIComponent(searchLocation)}&resultsToTake=15`;
    const data = await safeFetch(reedUrl, {
      headers: { 'Authorization': `Basic ${reedAuth}` }
    });
    if (data?.results) {
      for (const j of data.results) {
        allJobs.push({
          externalId: `reed-${j.jobId}`,
          title: j.jobTitle || '',
          company: j.employerName || 'Unknown',
          location: j.locationName || '',
          description: (j.jobDescription || '').substring(0, 3000),
          source: 'reed',
          url: j.jobUrl || '',
          salary: j.minimumSalary ? `${j.minimumSalary}-${j.maximumSalary}` : null,
          postedAt: j.date || null
        });
      }
    }
  } catch (e) { /* reed failed */ }
}

// Deduplicate by externalId
const seen = new Set();
const uniqueJobs = [];
for (const job of allJobs) {
  if (!seen.has(job.externalId) && job.title && job.description.length > 50) {
    seen.add(job.externalId);
    uniqueJobs.push(job);
  }
}

if (uniqueJobs.length === 0) return [];

return uniqueJobs.map(job => ({
  json: {
    ...job,
    userId: user.userId,
    masterCvText: user.masterCvText,
    subscriptionStatus: user.subscriptionStatus,
    creditsRemaining: user.creditsRemaining
  }
}));

// Parse scoring response, carry forward job + user data
const item = $input.first();
const prev = $('Fetch & Normalize All Job Sources').item;

try {
  const text = item.json.content?.[0]?.text || '';
  let jsonStr = text;
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) jsonStr = m[1];
  const p = JSON.parse(jsonStr.trim());

  return [{ json: {
    ...prev.json,
    compatibilityScore: p.compatibility_score || 0,
    atsKeywords: p.ats_keywords || [],
    matchingStrengths: p.matching_strengths || [],
    gaps: p.gaps || [],
    recommendation: p.recommendation || 'skip'
  }}];
} catch (e) {
  return [{ json: {
    ...prev.json,
    compatibilityScore: 0,
    atsKeywords: [],
    matchingStrengths: [],
    gaps: [],
    recommendation: 'skip'
  }}];
}

// Parse tailoring response
const item = $input.first();
const prev = $('Score >= 70?').first().json;

try {
  const text = item.json.content?.[0]?.text || '';
  let jsonStr = text;
  const m = text.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (m) jsonStr = m[1];
  const p = JSON.parse(jsonStr.trim());

  return [{ json: {
    ...prev,
    tailoredCvMarkdown: p.tailored_cv_markdown || '',
    coverLetterMarkdown: p.motivation_letter_markdown || '',
    status: 'tailored'
  }}];
} catch (e) {
  return [{ json: {
    ...prev,
    tailoredCvMarkdown: '',
    coverLetterMarkdown: '',
    status: 'discovered'
  }}];
}

// For low-scoring jobs (score < 70), mark as discovered only
const item = $input.first().json;

return [{ json: {
  ...item,
  tailoredCvMarkdown: null,
  coverLetterMarkdown: null,
  status: 'discovered'
}}];

// Collect all processed jobs (tailored + discovered) for this user
// and send them to the web app in a single batch callback
const items = $input.all();
const config = $('Load Config').first().json;

if (items.length === 0) return [];

// Group by userId
const byUser = {};
for (const item of items) {
  const d = item.json;
  if (!byUser[d.userId]) byUser[d.userId] = [];
  byUser[d.userId].push({
    externalId: d.externalId,
    title: d.title,
    company: d.company,
    location: d.location,
    description: d.description,
    source: d.source,
    url: d.url,
    salary: d.salary,
    postedAt: d.postedAt,
    compatibilityScore: d.compatibilityScore,
    atsKeywords: d.atsKeywords,
    matchingStrengths: d.matchingStrengths,
    gaps: d.gaps,
    recommendation: d.recommendation,
    tailoredCvMarkdown: d.tailoredCvMarkdown || null,
    coverLetterMarkdown: d.coverLetterMarkdown || null,
    status: d.status
  });
}

const appUrl = config.appUrl || 'https://autoapply.works';
const secret = config.webhookSecret || '';

for (const [userId, apps] of Object.entries(byUser)) {
  try {
    await fetch(`${appUrl}/api/webhooks/n8n`, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-webhook-secret': secret
      },
      body: JSON.stringify({
        type: 'new_applications',
        data: { userId, applications: apps }
      })
    });
  } catch (e) {
    console.log(`Callback failed for user ${userId}:`, e.message);
  }
}

return [{ json: { processed: items.length, users: Object.keys(byUser).length } }];

// Error handler — log to workflow_errors via web app
const error = $input.first().json;
const config = $('Load Config').first().json;
const appUrl = config.appUrl || 'https://autoapply.works';
const secret = config.webhookSecret || '';

try {
  await fetch(`${appUrl}/api/webhooks/n8n`, {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-webhook-secret': secret
    },
    body: JSON.stringify({
      type: 'workflow_error',
      data: {
        workflowId: 'job-discovery-pipeline',
        nodeName: error.node?.name || 'unknown',
        errorType: error.type || 'UNKNOWN',
        message: error.message || 'Unknown error',
        payload: JSON.stringify(error)
      }
    })
  });
} catch (e) {
  console.log('Error logging failed:', e.message);
}

return [{ json: { logged: true } }];
